<template>
 <div class="container-sm" >
    <div class="row justify-content-center">
        <div class="col-12 col-md-12 m-5 " style="width:700px;">
            <h3 class="mb-4">管理員登入</h3>
            <h5 class="text-danger mb-3">***僅限管理員進行操作***</h5>
            <div class="mb-3 row ">
                <p  class="col-sm-2 col-form-a my-auto">帳號</p>
                <div class="col-sm-10 border-bottom">
                <input v-model="account" type="text" class="form-control border-0 " id="account" >
                </div>
            </div>
            <div class="mb-3 row">
                <p  class="col-sm-2 col-form-a my-auto">Password</p>
                <div class="col-sm-10 border-bottom">
                <input v-model="password"  type="password" class="form-control border-0" id="password" >
                </div>
            </div>
           

            <div class="d-flex justify-content-center">
            <button @click="adminLogin" id="loginbtn" class="btn btn-secondary">
                <template  v-if="!isLoading">
                    登入
                </template>
                <template v-if="isLoading">
                    <div class="spinner-border spinner-border-sm" role="status">
                        <span class="visually-hidden">Loading...</span>
                    </div>
                </template>
            
            </button>
            </div>
           
        </div>
    </div>
  </div>
  <div class="position-fixed bottom-0 end-0 p-3" style="z-index: 5">
    <div id="loginfailtoast" class="toast bg-danger bg-gardient text-white border-0" role="alert" aria-live="assertive" aria-atomic="true">
        <div class="toast-header">
        <strong class="me-auto">警告</strong>
        <button type="button" class="btn-close" data-bs-dismiss="toast" aria-label="Close"></button>
        </div>
        <div class="toast-body">
            帳號或密碼錯誤
        </div>
    </div>
  </div>
</template>

<script>
import {ref,reactive,toRefs,toRaw} from 'vue'
import {useRouter} from 'vue-router'
import axios from 'axios'
import bootstrap from '../../../node_modules/bootstrap/dist/js/bootstrap.js'

export default {
 name:'BackEndLogin',
 setup(){
    let router=useRouter()
    let isLoading =ref(false)
    let loginInfo= reactive({
        account:'',
        password:''
    })

    function adminLogin(){
        axios.post('/adminlogin',toRaw(loginInfo),{headers:{'contentType':'application/json'}}).then(
        response =>{
            console.log(response.data)
            localStorage.setItem('isAdminLogin',response.data.isAdminLogin)
            if(localStorage.getItem('isAdminLogin')=='loginFailure' || localStorage.getItem('isAdminLogin') =='undefined'){
                var loginfailtoast=new bootstrap.Toast(document.getElementById('loginfailtoast'))
                loginfailtoast.show(    )
            }else{
                router.push('/backenddashboard/home')
            }
        }
        ).catch(
            error =>{
                console.log(error.message)
            }
        )
    }

    return {
        isLoading,
        ...toRefs(loginInfo),
        adminLogin
    }
 }


}
</script>

